class Solution {
    // Rotate the array to the right by k positions
    rotateRight(arr, k) {
        const n = arr.length;
        if (n === 0) return;

        k = k % n;

        // Store last k elements
        const temp = arr.slice(n - k);

        // Shift remaining elements
        for (let i = n - k - 1; i >= 0; i--) {
            arr[i + k] = arr[i];
        }

        // Copy stored elements to the front
        for (let i = 0; i < k; i++) {
            arr[i] = temp[i];
        }
    }

    // Rotate the array to the left by k positions
    rotateLeft(arr, k) {
        const n = arr.length;
        if (n === 0) return;

        k = k % n;

        // Store first k elements
        const temp = arr.slice(0, k);

        // Shift remaining elements
        for (let i = k; i < n; i++) {
            arr[i - k] = arr[i];
        }

        // Copy stored elements to the end
        for (let i = 0; i < k; i++) {
            arr[n - k + i] = temp[i];
        }
    }
}

